const prev = $('Resolve Recipient').first().json;
const geminiResp = $input.first().json;
let simplifiedError = prev.errorMessage;
try { simplifiedError = geminiResp.candidates[0].content.parts[0].text.trim(); } catch (e) {}
return [{ json: { ...prev, simplifiedError } }];

// Single-item flow: lookup returned the freshly inserted row (includes row_number).
// Job data is in $input (from Edit Fields, row_number stripped).
const submission = $('Lookup Inserted Row').first().json;
const job = $input.first().json;
return [{ json: { ...submission, ...job } }];

// Combine by position: submission+job (Pass TRUE items) with coords (Get Property Coordinates).
const submissionItems = $('Pass TRUE items').all();
const coordsItems = $('Refining feilds').all();
const len = Math.min(submissionItems.length, coordsItems.length);
if (len === 0) return [];
const out = [];
for (let i = 0; i < len; i++) {
  const sub = submissionItems[i]?.json || {};
  const coord = coordsItems[i]?.json || {};
  out.push({ json: { ...sub, ...coord } });
}
return out;

// Haversine distance in meters. Input = Merge output (submission+job+coords combined by position).
const items = $input.all();
const R = 6371000;
const toRad = deg => deg * (Math.PI / 180);
return items.map(item => {
  const j = item.json || {};
  const userLat = parseFloat(j.gpsLat);
  const userLng = parseFloat(j.gpsLng);
  const propertyLat = parseFloat(j.latitude);
  const propertyLng = parseFloat(j.longitude);
  let distance = NaN;
  if (Number.isFinite(userLat) && Number.isFinite(userLng) && Number.isFinite(propertyLat) && Number.isFinite(propertyLng)) {
    const dLat = toRad(propertyLat - userLat);
    const dLng = toRad(propertyLng - userLng);
    const a = Math.sin(dLat/2)*Math.sin(dLat/2) + Math.cos(toRad(userLat))*Math.cos(toRad(propertyLat))*Math.sin(dLng/2)*Math.sin(dLng/2);
    const c = 2 * Math.atan2(Math.sqrt(a), Math.sqrt(1-a));
    distance = R * c;
  }
  return { json: { ...j, distance: Number.isFinite(distance) ? distance : 999999 } };
});

